from langchain.agents import create_doctor_agent, AgentExecutor
from vex import verify

agent = create_doctor_agent(llm, tools=medical_tools)
agent_executor = AgentExecutor(agent=agent, max_iterations=5)

@verify(policies=["no-infinite-loop", "audit-decisions", "fda-part11"])
def safe_diagnosis(symptoms: str) -> dict:
    return agent_executor.invoke({"input": symptoms})

result = safe_diagnosis("chest pain, age 65, diabetic")

import { ChatOpenAI } from "langchain/chat_models/openai";
import { LLMChain } from "langchain/chains";
import { verify } from "vex-sdk";

const llm = new ChatOpenAI({ modelName: "gpt-4" });
const chain = new LLMChain({
  llm,
  prompt: triagePrompt
});

const compliantTriage = verify([
  "context-limit:8000",
  "json-schema:ehr-triage",
  "no-phi-leak"
]);

const result = await compliantTriage(async (input: string) => {
  const tokens = await llm.getNumTokens(input);
  if (tokens > 7000) throw new Error("Context overflow");
  return chain.call({ symptoms: input });
})("chest pain radiating to arm");

console.log(result);
